		templ_7745c5c3_Err = templruntime.WriteString(templ_7745c5c3_Buffer, 127, "\"><div><label class=\"block text-body font-medium text-text\">Reason *</label> <input type=\"text\" name=\"void_reason\" x-model=\"voidReason\" maxlength=\"500\" placeholder=\"Enter reason for voiding...\" class=\"mt-2 block w-full rounded-md border border-border-input bg-surface px-3 py-2 text-body text-text outline-none focus:ring-2 focus:ring-primary-focus [color-scheme:dark]\"><p x-show=\"voidSubmitted && !voidReason.trim()\" class=\"mt-1 text-small text-danger\">Reason is required.</p></div><div class=\"mt-6 flex items-center justify-end gap-3\"><button type=\"button\" @click=\"showVoidModal = false\" class=\"rounded-md border border-border px-4 py-2 text-body font-semibold text-text hover:bg-background\">Cancel</button> <button type=\"submit\" @click=\"voidSubmitted = true; if (!voidReason.trim()) $event.preventDefault()\" class=\"rounded-md bg-danger px-4 py-2 text-body font-semibold text-white hover:bg-danger-hover\">Void Reconciliation</button></div></form></div></div></div><script>\r\n\t\tfunction reconcilePage() {\r\n\t\t\treturn {\r\n\t\t\t\theader: { account_id: \"\", statement_date: \"\", ending_balance: \"\" },\r\n\t\t\t\tendingBalance: 0,\r\n\t\t\t\tbeginningBalance: 0,\r\n\t\t\t\tcandidates: [],  // [{id: string, amount: number}]\r\n\t\t\t\tselected: [],    // string IDs of checked lines\r\n\r\n\t\t\t\tshowVoidModal: false,\r\n\t\t\t\tvoidRecID: 0,\r\n\t\t\t\tvoidDate: \"\",\r\n\t\t\t\tvoidReason: \"\",\r\n\t\t\t\tvoidSubmitted: false,\r\n\r\n\t\t\t\tinit() {\r\n\t\t\t\t\tconst url = new URL(window.location.href);\r\n\t\t\t\t\tthis.header.account_id     = url.searchParams.get(\"account_id\")     || \"\";\r\n\t\t\t\t\tthis.header.statement_date = url.searchParams.get(\"statement_date\") || \"\";\r\n\t\t\t\t\tthis.header.ending_balance = url.searchParams.get(\"ending_balance\") || \"\";\r\n\r\n\t\t\t\t\tconst eb = parseFloat(url.searchParams.get(\"ending_balance\") || \"0\");\r\n\t\t\t\t\tthis.endingBalance = isNaN(eb) ? 0 : eb;\r\n\r\n\t\t\t\t\tconst bb = parseFloat(this.$el.dataset.beginning || \"0\");\r\n\t\t\t\t\tthis.beginningBalance = isNaN(bb) ? 0 : bb;\r\n\r\n\t\t\t\t\ttry {\r\n\t\t\t\t\t\tconst raw = JSON.parse(this.$el.dataset.candidates || \"[]\");\r\n\t\t\t\t\t\tthis.candidates = raw.map(c => ({ id: String(c.id), amount: parseFloat(c.amount) || 0 }));\r\n\t\t\t\t\t} catch (_) { this.candidates = []; }\r\n\r\n\t\t\t\t\t// Pre-select lines from accepted suggestions.\r\n\t\t\t\t\ttry {\r\n\t\t\t\t\t\tconst accepted = JSON.parse(this.$el.dataset.acceptedLines || \"[]\");\r\n\t\t\t\t\t\tfor (const id of accepted) {\r\n\t\t\t\t\t\t\tconst sid = String(id);\r\n\t\t\t\t\t\t\tif (!this.selected.includes(sid)) {\r\n\t\t\t\t\t\t\t\tthis.selected.push(sid);\r\n\t\t\t\t\t\t\t}\r\n\t\t\t\t\t\t}\r\n\t\t\t\t\t} catch (_) {}\r\n\t\t\t\t},\r\n\r\n\t\t\t\tselectedNet() {\r\n\t\t\t\t\treturn this.selected.reduce((sum, id) => {\r\n\t\t\t\t\t\tconst c = this.candidates.find(c => c.id === id);\r\n\t\t\t\t\t\treturn c ? sum + c.amount : sum;\r\n\t\t\t\t\t}, 0);\r\n\t\t\t\t},\r\n\r\n\t\t\t\tclearedBalance() { return this.beginningBalance + this.selectedNet(); },\r\n\t\t\t\tdifference()     { return this.endingBalance - this.clearedBalance(); },\r\n\t\t\t\tdiffOk()         { return Math.abs(this.difference()) < 0.005; },\r\n\r\n\t\t\t\tfmt(n) {\r\n\t\t\t\t\tconst v = typeof n === \"number\" ? n : parseFloat(n) || 0;\r\n\t\t\t\t\treturn v.toFixed(2);\r\n\t\t\t\t},\r\n\r\n\t\t\t\ttoggleAll(e) {\r\n\t\t\t\t\tif (e.target.checked) {\r\n\t\t\t\t\t\tthis.selected = this.candidates.map(c => c.id);\r\n\t\t\t\t\t} else {\r\n\t\t\t\t\t\tthis.selected = [];\r\n\t\t\t\t\t}\r\n\t\t\t\t},\r\n\r\n\t\t\t\topenVoidModal(recID, date) {\r\n\t\t\t\t\tthis.voidRecID = recID;\r\n\t\t\t\t\tthis.voidDate  = date;\r\n\t\t\t\t\tthis.voidReason = \"\";\r\n\t\t\t\t\tthis.voidSubmitted = false;\r\n\t\t\t\t\tthis.showVoidModal = true;\r\n\t\t\t\t},\r\n\r\n\t\t\t\tbeforeSave(_e) {\r\n\t\t\t\t\t// Save is always allowed regardless of difference — no validation needed.\r\n\t\t\t\t},\r\n\r\n\t\t\t\tbeforeSubmit(e) {\r\n\t\t\t\t\tif (!this.diffOk()) e.preventDefault();\r\n\t\t\t\t},\r\n\t\t\t};\r\n\t\t}\r\n\t</script>")
